package com.example.lessondesign.controller; import org.springframework.core.io.InputStreamResource; import org.springframework.core.io.Resource; import org.springframework.http.*; import org.springframework.web.bind.annotation.*; import java.io.InputStream; @RestController @RequestMapping("/api") public class TemplateController { @GetMapping("/download-template") public ResponseEntity<Resource> downloadTemplate(){ try{ InputStream is=getClass().getResourceAsStream("/static/templates/student_template.xlsx"); if(is==null) return ResponseEntity.status(500).body(null); return ResponseEntity.ok().header(HttpHeaders.CONTENT_DISPOSITION,"attachment; filename=student_template.xlsx").contentType(MediaType.parseMediaType("application/vnd.ms-excel")).body(new InputStreamResource(is)); }catch(Exception e){ return ResponseEntity.status(500).body(null); } } }